--TABLA EMPLEADOS
--DESCRIPCION ---ALMACENA LA INFORMACION BASICA DE LOS EMPLEADOS DEL SISTEMA

--ID DEL UNICO EMPLEADO DE TIPO NUMERICO POR LO SE UTILIZARA NUMBER
--GENERATED BY DEFAULT AS IDENTITY: 
--GENERA AUTOMATICAMENTE EL IDENTIFICADOR DE CADA EMPLEADO
--PRIMARY KEY:
--DEFINE LA LLAVE PRIMARIA DE LA TABLA-
CREATE TABLE EMPLEADOS (
ID_EMPLEADOS NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
NOMBRE VARCHAR2 (100 CHAR) NOT NULL,
PUESTO VARCHAR2 (100 CHAR) NOT NULL,   --NOT NULL ES UN CAMPO OBLIGATORIO  
SALARIO NUMBER ( 10, 2) NOT NULL   --sE MANEJA CON CON 10 DIGITOS Y 2 DECIMALES.
);

--INDICE MEJORA EL RENDIMIENTO DE BUSQUEDA
ALTER TABLE EMPLEADOS
ADD CONSTRAINT CHK_SALARIO_POSITIVO
CHECK(SALARIO > 0);

--INDICE
CREATE INDEX IDX_EMPLEADOS_NOMBRE
ON EMPLEADOS(NOMBRE);

CREATE INDEX IDX_EMPLEADOS_PUESTO
ON EMPLEADOS(PUESTO);

--IINSERCION DE VALORES
INSERT INTO EMPLEADOS (NOMBRE, PUESTO, SALARIO)
VALUES ('Juan Perez', 'Desarrollador Java', 25000);

